import { useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import CustomerForm, { normalizeCustomerForm } from "../components/CustomerForm";
import API, { getApiError } from "../services/api";

export default function EditCustomer() {
  const navigate = useNavigate();
  const { customerId } = useParams();
  const [customer, setCustomer] = useState(null);
  const [form, setForm] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    const loadCustomer = async () => {
      setLoading(true);
      setError("");

      try {
        const response = await API.get(`/customers/${customerId}`);
        setCustomer(response.data);
        setForm(normalizeCustomerForm(response.data));
      } catch (requestError) {
        setError(getApiError(requestError, "Unable to load this customer."));
      } finally {
        setLoading(false);
      }
    };

    loadCustomer();
  }, [customerId]);

  const updateField = (key, value) => {
    setForm((current) => ({ ...current, [key]: value }));
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    setError("");

    if (!form.fullName || !form.phone || !form.age || !form.amountPaid) {
      setError("Please fill in name, phone, age, and amount paid before saving.");
      return;
    }

    setSaving(true);

    try {
      await API.put(`/customers/${customerId}`, {
        ...form,
        age: Number(form.age),
        amountPaid: Number(form.amountPaid)
      });

      navigate("/customers", {
        state: { message: `${form.fullName} was updated successfully.` }
      });
    } catch (requestError) {
      setError(getApiError(requestError, "Unable to update this customer."));
    } finally {
      setSaving(false);
    }
  };

  if (loading) {
    return <div className="panel-empty">Loading customer details...</div>;
  }

  if (!form || !customer) {
    return (
      <div className="page-stack">
        <div className="status-banner status-banner--error">
          {error || "Customer not found."}
        </div>
      </div>
    );
  }

  return (
    <CustomerForm
      eyebrow="Member updates"
      title={`Edit ${customer.fullName}`}
      description="Update member details without changing their customer ID or attendance history."
      form={form}
      error={error}
      saving={saving}
      submitLabel="Save changes"
      savingLabel="Saving..."
      onSubmit={handleSubmit}
      onChange={updateField}
      secondaryAction={() => navigate("/customers")}
      secondaryLabel="Cancel"
      previewStartDate={customer.planStart || new Date().toISOString().split("T")[0]}
      previewNote="Changing the plan recalculates the end date from the member's existing start date."
    />
  );
}
